i# to snap values to the nearest notch or bottom/top of the slider range,
# hold down ctrl for x, and/or or alt for y 

def offToOn(panelValue):
	pan = parent()
	ppar = parent().par
	ppanel = parent().panel

	if panelValue.name=='select' :		
		if ppar.Interactiontype == 'absolute' :
			pass
		else:		
			pan.store('inituv', ppanel.u.val if ppar.Interactiontype == 'relativeu' else ppanel.v.val )			
			pan.store('Value1', ppar.Value1.eval())

	if ppar.Mappable :
		root.store('galLatest', parent())

	return 

def whileOn(panelValue):
	pan = parent()
	ppar = parent().par
	ppanel = parent().panel

	if panelValue.name=='select' :			

		if ppar.Interactiontype == 'absolute' :
			pass
		else:		
			valuv = ppanel.u.val if ppar.Interactiontype == 'relativeu' else ppanel.v.val
			low1 = ppar.Rangelow1.eval()
			high1 = ppar.Rangehigh1.eval()

			val1 = pan.fetch('Value1', 0.) + (valuv-pan.fetch('inituv', 0.)) * (high1 - low1) * ppar.Relativemult

			val1 = low1 if (ppar.Clamplow1 and val1 < low1) else val1
			val1 = high1 if (ppar.Clamphigh1 and val1 > high1) else val1

			if ppar.Push1 :
				try:
					prefix = 'parent().' if (ppar.Value1.expr[0:6]=='parent') else 'parent(2).'
					pushpar = eval(prefix+ppar.Value1.expr)
					pushpar.val = val1
				except:
					pass
			else:
				ppar.Value1 = val1

	return

def valueChange(panelValue):

	ppar = parent().par
	ppanel = parent().panel

	# alt-m or ctrl-m to map channel to this gadget value
	if panelValue.name=='key' :
		if panelValue.val == 109 and (ppanel.alt==1 or ppanel.ctrl==1) :
			try:
				op('/gal/mapper/assign').run(parent().path, 'Value1')
			except:
				pass
		return

	if panelValue.name=='select' or ppar.Interactiontype != 'absolute':			
		return

	dclick=0
	if panelValue.name=='click' :
		if panelValue.val==2:
			dclick=1
			val1 = ppar.Value1.normVal
		else:
			return
	else:
		angle = math.atan2((ppanel.v-.5)*(parent().height/parent().width), (ppanel.u-.5)) * 180/math.pi
		if angle<-90 : 
			angle = angle + 360
		if angle > ppar.Arcanglelow :
			angle = ppar.Arcanglelow
		if angle < ppar.Arcanglehigh :
			angle = ppar.Arcanglehigh

		val1 = (ppar.Arcanglelow-angle)/(ppar.Arcanglelow-ppar.Arcanglehigh)
		#print(angle, (angle-90)%360, 360 + angle - ppar.Arcanglelow, val1)

	val1 = discrete(val1, dclick)

	#now set final value
	val1 = ppar.Rangelow1 + val1 * (ppar.Rangehigh1 - ppar.Rangelow1) 

	if ppar.Push1 :
		try:
			prefix = 'parent().' if (ppar.Value1.expr[0:6]=='parent') else 'parent(2).'
			pushpar = eval(prefix+ppar.Value1.expr)
			pushpar.val = val1
		except:
			pass
	else:
		ppar.Value1 = val1

	return

def discrete(val1, dclick):
	ppar = parent().par
	ppanel = parent().panel

	#deal with notches and ctrl-click and shift-click
	if ppanel.ctrl==1 or dclick==1 :

		default1 = (ppar.Default1 - ppar.Rangelow1) / (ppar.Rangehigh1 - ppar.Rangelow1) 

		try:
			notches = eval(ppar.Notches.val)
			notches = [ 0 ] + notches + [ 1, default1 ]

		except:
			notches = [ 0, 1, default1 ]

		dist = [ abs(val1-n) for n in notches ]

		indx = dist.index(min(dist))

		val1 = notches[indx]

	#deal with integers
	if ppar.Integer > 0 :
		ivals = []
		for v in range(int(ppar.Rangelow1), int(ppar.Rangehigh1+1)) :
			ivals = ivals + [ (v - ppar.Rangelow1) / (ppar.Rangehigh1 - ppar.Rangelow1) ]

		dist = [ abs(val1-n) for n in ivals ]	

		indx = dist.index(min(dist))
		val1 = ivals[indx]

	return val1

