def setupParameters(scriptOP):
	return

def cook(scop):
	ppar = parent().par
	scop.clear()

	collist = ['name', 'short', 'token', 'icon', 'help', 'command', 'x', 'y', 'w', 'h']

	scop.appendRow( collist ) 

	in1 = op('in1')

	if in1.numRows>1 :

		for i in range(1,in1.numRows) :
			name = in1[i,'name']
			if name == None :
				name = str(i)
			short = in1[i,'short']
			if short == None :
				short = name
			token = in1[i,'token']
			if token == None :
				token = 'item' + str(i)
			icon = in1[i,'icon']
			if icon == None :
				icon = ''
			help = in1[i,'help']
			if help == None :
				help = ''
			command = in1[i,'command']
			if command == None :
				command = ''

			if icon != ''  and icon != None:
				if icon.val[0] != '/' :
					level = 3 if parent(2).par.inshortcut == 'menu' else 2
					icon = parent(level).path + '/' + icon
			scop.appendRow( [name, short, token, icon, help, command, '', '', '', ''] ) 

		# new: append unused columns
		for j in range(0,in1.numCols) : 
			if str(in1[0,j])  not in collist :
				colcells = []
				for i in range(0,in1.numRows) :
					colcells = colcells + [ in1[i,j] ]
				scop.appendCol( colcells ) 


	else:
		try: butnames = eval(ppar.Names.eval())
		except: butnames = [ ]

		try: iconpaths = eval(ppar.Icontops.eval())
		except: iconpaths = [ ]

		if ppar.Indicator=='text' :	
			for t in butnames :
				scop.appendRow( [t, '', ''] ) 

		elif ppar.Indicator=='texticon' :
			for t,ip in zip(butnames, iconpaths) :
				if ip[0]!='/' :
					ip = '../' + ip
				scop.appendRow( [t, '', '', ip] ) 

		else:		
			for ip in iconpaths :
				if ip[0]!='/' :
					ip = '../' + ip
				scop.appendRow( ['', '', '', ip, '', '', '', '', '', ''] ) 	


	if (scop.numRows < 2) :
		for t in ['1', '2' ] :
			scop.appendRow( [t] ) 


	aspectxy = 1	

	bw = parent().width
	bh = parent().height	

	nitems = scop.numRows-1

	llocate = ppar.Labellocate

	maxrows = ppar.Maxrows
	maxcols = ppar.Maxcols

	if ppar.Itemlayout=='horizontal' :
		ncols = nitems if nitems<maxcols else maxcols
		nrows = 1+int((nitems-1)/ncols) if nitems<(maxrows*maxcols) else maxrows

	else :
		nrows = nitems if nitems<maxrows else maxrows
		ncols = 1+int((nitems-1)/nrows) if nitems<(maxrows*maxcols) else maxcols

	gridw = bw
	gridh = bh
	gridx = gridy = 0

	if llocate=='left' :
		gridw = bw - ppar.Labelwidth
		gridh = bh
		gridx = int(ppar.Labelwidth)
	elif llocate=='top' :
		gridw = bw
		gridh = bh - ppar.Labelwidth
		gridy = 0
	elif llocate=='bottom' :
		gridw = bw
		gridh = bh - ppar.Labelwidth
		gridy = int(ppar.Labelwidth)	

	itemw = float(gridw) / ncols
	itemh = float(gridh) / nrows
	x = y = w = h = []
	for i in range(0, ncols) :
		x = x + [round(i * itemw)]
		w = w + [round((i+1) * itemw) - round(i * itemw)]

	for i in range(0, nrows) :
		y = y + [round(i * itemh)]
		h = h + [round((i+1) * itemh) - round(i * itemh)]

	if ppar.Itemlayout=='horizontal' :
		for i in range(1,scop.numRows) :
			col = ((i-1)%ncols)
			row = (nrows-1-int((i-1)/ncols))
			scop[i,'x'] = gridx + x[col]
			scop[i,'y'] = gridy + y[row]
			scop[i,'w'] = w[col]
			scop[i,'h'] = h[row]

	else :
		for i in range(1,scop.numRows) :
			col = int((i-1)/nrows)
			row = (nrows-1-((i-1)%nrows))
			scop[i,'x'] = gridx + x[col]
			scop[i,'y'] = gridy + y[row]
			scop[i,'w'] = w[col]
			scop[i,'h'] = h[row]			
	return

