*�����������������T# to snap values to the nearest notch or bottom/top of the slider range,
# or the default value, hold down ctrl and/or alt while moving the slider
# or doubleclick on the slider

def valueChange(panelValue):

	ppar = parent().par
	ppanel = parent().panel

	# ctrl-f switches the three Number Field modes if slider is horizontal
	# alt-m assigns channel in /gal/mapper to this gadget

	if panelValue.name=='key' :
		if panelValue.val == 102 and ppanel.ctrl :
			if op('flip').par.npasses==0 :
				parent().par.Numfield = (int(parent().par.Numfield)+1)%3

		elif panelValue.val == 109 and (ppanel.alt==1 or ppanel.ctrl==1) :
			try:
				op('/gal/mapper/assign').run(parent().path, 'Value1')
			except:
				pass
		return

	dclick=0
	if panelValue.name=='click' :
		if panelValue.val==2 :
			dclick=1
			val = ppar.Value1.normVal
		else:
			return
	else:
		val = panelValue.val

	if ppanel.alt or ppanel.ctrl or dclick :

		default = (ppar.Default1 - ppar.Rangelow1) / (ppar.Rangehigh1 - ppar.Rangelow1) 

		try:
			notches = eval(ppar.Notches.val)
			notches = [ 0 ] + notches + [ 1, default ]

		except:
			notches = [ 0, 1, default ]

		dist = [ abs(val-n) for n in notches ]	

		indx = dist.index(min(dist))
		val = notches[indx]

	if ppar.Integer > 0 :
		ivals = []
		for v in range(int(ppar.Rangelow1), int(ppar.Rangehigh1+1)) :
			ivals = ivals + [ (v - ppar.Rangelow1) / (ppar.Rangehigh1 - ppar.Rangelow1) ]

		dist = [ abs(val-n) for n in ivals ]	

		indx = dist.index(min(dist))
		val = ivals[indx]

	val1 = ppar.Rangelow1 + val * (ppar.Rangehigh1 - ppar.Rangelow1) 

	if ppar.Push1 :
		try:
			prefix = 'parent().' if (ppar.Value1.expr[0:6]=='parent') else 'parent(2).'
			pushpar = eval(prefix+ppar.Value1.expr)
			pushpar.val = val1
		except:
			pass
	else:
		ppar.Value1 = val1

	if ppar.Mappable :
		root.store('galLatest', parent())

		return

