ms = op('multiSelect')

def offToOn(panelValue):

	ppar = parent().par
	myIndex = panelValue.owner.digits-1

	if ppar.Enableselect :
		itemop = panelValue.owner
		if itemop.panel.ctrl :
			ms[0,0] = str(list(set(eval(ms[0,0].val) + [myIndex])))
			return
		elif itemop.panel.shift :
			v = int(parent().par.Value1)
			seq = list(range(min(myIndex,v),1+max(myIndex,v)))
			ms[0,0] = str(list(set(eval(ms[0,0].val) + seq)))
			return
		else:
			ms[0,0] = str([myIndex])
	else:
		ms[0,0] = '[]'

	radiotype = ppar.Radiotype

	if radiotype == 'radiodown' or radiotype == 'radioup':
		val1 = myIndex
	else:	
		prev = ppar.Value1
		if prev != myIndex :
			val1 = panelValue.owner.digits-1
		else:
			val1 = -1

	if ppar.Push1 :
		try:
			prefix = 'parent().' if (ppar.Value1.expr[0:6]=='parent') else 'parent(2).'
			pushpar = eval(prefix+ppar.Value1.expr)
			pushpar.val = val1
		except:
			pass
	else:
		ppar.Value1 = val1

	plevel = 3 if parent(2).par.inshortcut == 'menu' else 2

	cmd = op('items')[myIndex+1,'command']
	if cmd != '' :
		run('index = ' + str(myIndex) + ' ; ' + cmd, fromOP=parent(plevel))
	if ppar.Runofftoon != '' :
		run('index = ' + str(myIndex) + ' ; ' + ppar.Runofftoon, fromOP=parent(plevel))

	if ppar.Mappable :
		try:
			op('/gal/latest')[0,0] = parent().path
		except:
			pass

	return

